class Solution:
    def maxProduct(self, nums: list[int]) -> int:
        n = len(nums)
        mx = nums[:]
        mn = nums[:]
        for i in range(1, n):
            cands = (nums[i], mx[i - 1] * nums[i], mn[i - 1] * nums[i])
            mx[i] = max(cands)
            mn[i] = min(cands)
        return max(mx)

