class Solution:
    def maxProduct(self, nums: list[int]) -> int:
        fmax = fmin = ans = nums[0]  # 同时维护「以当前结尾的最大积」与「最小积」
        for x in nums[1:]:
            # 负数会让最大变最小、最小变最大,故三者一起比
            cands = (x, fmax * x, fmin * x)
            fmax = max(cands)
            fmin = min(cands)
            ans = max(ans, fmax)
        return ans
